sql:
SELECT name, number_of_employees
FROM organizations
ORDER BY number_of_employees DESC;

SELECT "name", "total_assets"
FROM "organizations"
WHERE "total_income" > (SELECT AVG("total_income") FROM "organizations");

SELECT name AS Organization_Name, total_assets AS Maximum_Assets
FROM organizations
WHERE total_assets = (
    SELECT MAX(total_assets)
    FROM organizations
);

SELECT org_id, name, address, total_income, total_revenue, total_assets, contact_email
FROM organizations
ORDER BY total_assets DESC;

SELECT name, total_revenue
FROM organizations
WHERE total_revenue = (
  SELECT MAX(total_revenue)
  FROM organizations
);

SELECT DISTINCT organizations.name
FROM organizations
JOIN financial_transactions ON organizations.org_id = financial_transactions.org_id;

SELECT AVG(total_assets) 
FROM organizations 
WHERE org_id IN (SELECT org_id FROM projects);
